import osimport argparsefrom sendgrid import SendGridAPIClientfrom sendgrid.helpers.mail import Mailfrom dotenv import load_dotenvload_dotenv()SENDGRID_API_KEY = os.getenv("SENDGRID_API_KEY")SENDER_EMAIL = os.getenv("SENDER_EMAIL")def dispatch_email(to_email, subject, draft_file):    if not SENDGRID_API_KEY or not SENDER_EMAIL:        print("SendGrid keys missing from .env. Fallback required.")        return False    try:        with open(draft_file, 'r', encoding='utf-8') as f:            html_content = f.read()    except FileNotFoundError:        print(f"Draft file {draft_file} not found.")        return False    formatted_content = html_content.replace('\n', '<br>')    message = Mail(        from_email=SENDER_EMAIL,        to_emails=to_email,        subject=subject,        html_content=formatted_content)    try:        sg = SendGridAPIClient(SENDGRID_API_KEY)        response = sg.send(message)        print(f"Enterprise Dispatch Successful: {to_email} | SendGrid Status: {response.status_code}")        return True    except Exception as e:        print(f"SendGrid Dispatch Failed: {e}")        return Falseif __name__ == "__main__":    parser = argparse.ArgumentParser(description="Apex Enterprise Email Dispatcher")    parser.add_argument("--to", required=True, help="Target email address")    parser.add_argument("--subject", required=True, help="Email subject line")    parser.add_argument("--draft", required=True, help="Path to the draft text file")    args = parser.parse_args()    dispatch_email(args.to, args.subject, args.draft)